// Create web3 instance
const web3 = new Web3(new Web3.providers.HttpProvider(provider));

// Function to send ETH transaction
async function sendEthTransaction(recipient, amount) {
  const txCount = await web3.eth.getTransactionCount(privateKey);
  const rawTx = {
    from: privateKey,
    to: recipient,
    value: web3.utils.toWei(amount.toString(), 'ether'),
    gas: '20000',
    gasPrice: web3.utils.toWei('20', 'gwei')
  };
  const signedTx = await web3.eth.accounts.signTransaction(rawTx, privateKey);
  const txHash = await web3.eth.sendSignedTransaction(signedTx.rawTransaction.toString());
  return txHash;
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, functionName, args) {
  const contractAbi = require('./contract-abi.json');
  const contractInstance = new web3.eth.Contract(contractAbi, contractAddress);
  const result = await contractInstance.methods[functionName](...args).call();
  return result;
}

